// =====================================================================
//  CONCILIACIÓN STATEMENT vs (CAJERO Movimientos + CAJERO Depósitos + INGRESOS)
//  Regla de oro: FECHA primero (obligatoria), luego MONTO, luego TARJETA/cod.aut.
// =====================================================================
var ST = { fechaDep:0, fechaTrx:1, tarjeta:6, operacion:8, tipoTarjeta:9, tarjetaNum:10, codAut:12, checkout:17, total:23 };
var CJ  = { folioInd:1, fecha:2, abonos:10, referencia:13 };
var DEP = { folio:0, fecha:2, total:6, notas:8 };
var IN  = { ticket:1, fecha:2, propina:15, total:17, fp:18, pago:19, ref:23 };
var TOL_INGRESO = 1.0; // el statement a veces redondea a peso (937.3 -> 938)

// -------- Helpers --------
function toCells(json){
  if (Array.isArray(json)) return json;
  if (json && Array.isArray(json.row)) return json.row;
  var keys = Object.keys(json || {});
  var allNum = keys.length > 0 && keys.every(function(k){ return /^\d+$/.test(k); });
  if (allNum) { keys.sort(function(a,b){ return Number(a)-Number(b); }); }
  return keys.map(function(k){ return json[k]; });
}
function norm(v){ return String(v === null || v === undefined ? '' : v).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').trim(); }
function normHard(v){ return norm(v).replace(/[^a-z0-9]/g,''); }
function digits(v){ return String(v === null || v === undefined ? '' : v).replace(/\D/g,''); }
function last4(v){ var d = digits(v); return d.length >= 4 ? d.slice(-4) : d; }
function parseAmount(v){
  if (v === null || v === undefined || v === '') return NaN;
  if (typeof v === 'number') return Math.round(v*100)/100;
  var s = String(v).trim().replace(/[^0-9.,-]/g,''); if (s === '') return NaN;
  var lc = s.lastIndexOf(','), ld = s.lastIndexOf('.');
  if (lc > ld) { s = s.replace(/\./g,'').replace(',', '.'); } else { s = s.replace(/,/g,''); }
  var n = parseFloat(s); return isNaN(n) ? NaN : Math.round(n*100)/100;
}
function amountEq(a,b){ if (isNaN(a)||isNaN(b)) return false; return Math.abs(a-b) < 0.01; }
function pad(x){ x = String(x); return x.length < 2 ? '0'+x : x; }
function normDate(v){
  if (v === null || v === undefined) return '';
  if (typeof v === 'number') { var d0 = new Date(Date.UTC(1899,11,30) + v*86400000); return '' + d0.getUTCFullYear() + pad(d0.getUTCMonth()+1) + pad(d0.getUTCDate()); }
  var s = String(v).trim(); if (!s) return '';
  var m = s.match(/(\d{1,4})[\/.\-](\d{1,2})[\/.\-](\d{1,4})/);
  if (m){ var a=m[1],b=m[2],c=m[3],y,mo,d; if (a.length===4){y=a;mo=b;d=c;}else{d=a;mo=b;y=c;} if (y.length===2) y='20'+y; return y+pad(mo)+pad(d); }
  var t = Date.parse(s); if (!isNaN(t)){ var dt=new Date(t); return ''+dt.getFullYear()+pad(dt.getMonth()+1)+pad(dt.getDate()); }
  return norm(s);
}
function alnum(v){ return norm(v).replace(/[^a-z0-9]/g,''); }
// cod.aut robusto: núcleo de DÍGITOS (para 01018D con sufijo de red) + ALFANUMÉRICO (para letras: LDFBXT, IK526C).
function codMatch(stCod, refText){
  var sd = digits(stCod), sa = alnum(stCod);
  var rd = digits(refText), ra = alnum(refText);
  if (sd.length >= 5){
    if (rd.indexOf(sd) !== -1) return true;
    var sd2 = sd.replace(/^0+/,''); if (sd2.length >= 5 && rd.indexOf(sd2) !== -1) return true;
  }
  if (sa.length >= 5 && ra.indexOf(sa) !== -1) return true;
  return false;
}
function safeRows(name){ try { return $(name).all().map(function(i){ return toCells(i.json); }); } catch(e){ return []; } }
function findHeader(rows, markers){
  for (var r = 0; r < rows.length; r++){ var row = rows[r]; if (!row) continue;
    for (var c = 0; c < row.length; c++){ var cell = normHard(row[c]);
      for (var mi = 0; mi < markers.length; mi++){ if (cell === normHard(markers[mi])) return r; } } }
  return -1;
}
function findRowLike(rows, markers, startAt){
  for (var r = (startAt||0); r < rows.length; r++){ var row = rows[r]; if (!row) continue;
    var c0 = normHard(row[0]);
    for (var mi = 0; mi < markers.length; mi++){ if (c0 === normHard(markers[mi])) return r; } }
  return -1;
}

// -------- Cargar hojas --------
var stAll = safeRows('Extract Statement');
var cjAll = safeRows('Extract Cajero');
var inAll = safeRows('Extract Ingresos');

// -------- Statement: filas de datos --------
var stHdr = findHeader(stAll, ['cod. aut.', 'cod aut', 'codaut']);
var stData = (stHdr >= 0 ? stAll.slice(stHdr+1) : stAll.slice(1)).filter(function(row){
  return row && (norm(row[ST.fechaTrx]) !== '' || norm(row[ST.total]) !== '' || norm(row[ST.codAut]) !== '');
});
stData.sort(function(a,b){
  var ka = normDate(a[ST.fechaDep]), kb = normDate(b[ST.fechaDep]);
  if (ka < kb) return -1; if (ka > kb) return 1;
  var la = normDate(a[ST.fechaTrx]), lb = normDate(b[ST.fechaTrx]);
  if (la < lb) return -1; if (la > lb) return 1;
  return 0;
});

// -------- Cajero MOVIMIENTOS: por Folio Ind (cobros con fecha por cobro) --------
var cjHdr = findHeader(cjAll, ['folio ind']);
var cjEnd = findRowLike(cjAll, ['total','depositos','deposito','sub total caja','retiros de caja'], cjHdr>=0?cjHdr+1:0);
var cjSlice = cjAll.slice(cjHdr>=0?cjHdr+1:0, cjEnd>=0?cjEnd:cjAll.length);
var cjData = cjSlice.filter(function(row){ return row && norm(row[CJ.folioInd]) !== '' && norm(row[CJ.abonos]) !== ''; });
var cajeroFolios = {};
for (var ci = 0; ci < cjData.length; ci++){
  var crow = cjData[ci];
  var folio = String(crow[CJ.folioInd]);
  var abono = parseAmount(crow[CJ.abonos]);
  var cfecha = normDate(crow[CJ.fecha]);
  if (!cajeroFolios[folio]) cajeroFolios[folio] = { folio: folio, fechas: {}, sum: 0, charges: [] };
  cajeroFolios[folio].charges.push({ abono: abono, refText: crow[CJ.referencia], fecha: cfecha });
  if (!isNaN(abono)) cajeroFolios[folio].sum = Math.round((cajeroFolios[folio].sum + abono) * 100) / 100;
  if (cfecha) cajeroFolios[folio].fechas[cfecha] = true;
}

// -------- Cajero DEPOSITOS (segunda tabla) --------
var depositos = [];
var depHdr = findRowLike(cjAll, ['depositos','deposito']);
if (depHdr >= 0){
  var colHdr = findHeader(cjAll.slice(depHdr, depHdr+4), ['folio']);
  var depStart = depHdr + (colHdr >= 0 ? colHdr + 1 : 2);
  for (var dr = depStart; dr < cjAll.length; dr++){
    var drow = cjAll[dr]; if (!drow) continue;
    var dfolio = norm(drow[DEP.folio]);
    if (dfolio === '') continue;
    if (dfolio === 'total' || dfolio === 'retiros de caja' || dfolio === 'codigo' || dfolio === 'sub total caja') break;
    if (!/^ind\d+/.test(dfolio) && !/^mtr\d+/.test(dfolio)) continue;
    var dtotal = parseAmount(drow[DEP.total]);
    if (isNaN(dtotal)) continue;
    depositos.push({ folio: String(drow[DEP.folio]), fecha: normDate(drow[DEP.fecha]), total: dtotal, refText: drow[DEP.notas] });
  }
}

// -------- Ingresos: por TICKET (padre + sub-filas de pago/PROTC) --------
var inHdr = findHeader(inAll, ['ticket']);
var inData = inHdr >= 0 ? inAll.slice(inHdr+1) : inAll;
var ingresoTickets = {}; var curTicket = '';
for (var i = 0; i < inData.length; i++){
  var row = inData[i]; if (!row) continue;
  if (norm(row[IN.ticket]) !== ''){
    curTicket = String(row[IN.ticket]);
    if (!ingresoTickets[curTicket]) ingresoTickets[curTicket] = { ticket: curTicket, fecha: normDate(row[IN.fecha]), total: parseAmount(row[IN.total]), pays: [] };
  }
  var fp = norm(row[IN.fp]); var pago = parseAmount(row[IN.pago]); var ref4 = last4(row[IN.ref]);
  if (fp !== '' && !isNaN(pago) && curTicket !== '' && ingresoTickets[curTicket]){
    ingresoTickets[curTicket].pays.push({ fp: fp, pago: pago, ref4: ref4 });
  }
}

// -------- Matchers (todos exigen FECHA) --------
function folioHasDate(g, dateKey){ return dateKey !== '' && g.fechas[dateKey] === true; }

// Cajero fuerte: FECHA + cod.aut (llave única). El monto es refuerzo, NO requisito
// (liquidación internacional puede diferir del abono del Cajero).
function matchCajeroStrong(codAutRaw, total, dateKey){
  if (dateKey === '' || alnum(codAutRaw).length < 5) return null;
  for (var f in cajeroFolios){ var g = cajeroFolios[f];
    for (var c = 0; c < g.charges.length; c++){ var ch = g.charges[c];
      if (ch.fecha === dateKey && codMatch(codAutRaw, ch.refText)){
        var mismo = !isNaN(total) && amountEq(total, ch.abono);
        var diff = (!isNaN(total) && !isNaN(ch.abono)) ? Math.round((total - ch.abono)*100)/100 : NaN;
        return { folio: g.folio, montoFuente: ch.abono, diff: diff,
          detalle: 'Cajero: cobro individual (fecha + cod.aut' + (mismo ? ' + monto' : '; monto difiere -liquidación-') + ').' };
      } } }
  return null;
}
function matchDepositoStrong(codAutRaw, total, dateKey){
  if (dateKey === '' || alnum(codAutRaw).length < 5) return null;
  for (var i = 0; i < depositos.length; i++){ var d = depositos[i];
    if (d.fecha === dateKey && codMatch(codAutRaw, d.refText)){
      var mismo = !isNaN(total) && amountEq(total, d.total);
      var diff = (!isNaN(total) && !isNaN(d.total)) ? Math.round((total - d.total)*100)/100 : NaN;
      return { folio: d.folio, montoFuente: d.total, diff: diff,
        detalle: 'Cajero/Depósitos: fecha + cod.aut' + (mismo ? ' + monto' : '; monto difiere -liquidación-') + '.' };
    } }
  return null;
}
function matchIngreso(card4, dateKey, total){
  if (card4 === '' || isNaN(total) || dateKey === '') return null;
  var best = null, bestDiff = Infinity;
  for (var t in ingresoTickets){ var tk = ingresoTickets[t];
    if (tk.fecha !== dateKey) continue;
    var cardPays = [], protcSum = 0;
    for (var pi = 0; pi < tk.pays.length; pi++){ var pp = tk.pays[pi];
      if (pp.ref4 !== '' && pp.ref4 === card4) cardPays.push(pp);
      else if (pp.ref4 === '' && !isNaN(pp.pago)) protcSum += pp.pago; }
    if (cardPays.length === 0) continue;
    protcSum = Math.round(protcSum*100)/100;
    var sumCard = 0; for (var cp = 0; cp < cardPays.length; cp++){ sumCard += cardPays[cp].pago; } sumCard = Math.round(sumCard*100)/100;
    var cands = [];
    for (var cp2 = 0; cp2 < cardPays.length; cp2++){ cands.push(cardPays[cp2].pago); cands.push(Math.round((cardPays[cp2].pago + protcSum)*100)/100); }
    cands.push(sumCard); cands.push(Math.round((sumCard + protcSum)*100)/100);
    if (!isNaN(tk.total)) cands.push(tk.total);
    for (var cd = 0; cd < cands.length; cd++){ var diff = Math.abs(total - cands[cd]); if (diff < bestDiff){ bestDiff = diff; best = tk.ticket; } }
  }
  if (best !== null && bestDiff <= TOL_INGRESO)
    return { ticket: best, detalle: 'Ingresos: ticket (fecha + tarjeta ' + card4 + ' + monto' + (bestDiff >= 0.01 ? ', dif '+bestDiff.toFixed(2) : '') + ').' };
  return null;
}
function matchCajeroByAmountDate(total, dateKey){
  if (isNaN(total) || dateKey === '') return null;
  for (var f in cajeroFolios){ var g = cajeroFolios[f];
    if (!folioHasDate(g, dateKey) || !amountEq(total, g.sum)) continue;
    var extra = g.charges.length > 1 ? ' (' + g.charges.length + ' cobros sumados)' : '';
    return { folio: g.folio, detalle: 'Cajero: suma de cobros del Folio Ind por fecha + monto' + extra + '.' }; }
  return null;
}
function matchDepositoByAmountDate(total, dateKey){
  if (isNaN(total) || dateKey === '') return null;
  for (var i = 0; i < depositos.length; i++){ var d = depositos[i];
    if (d.fecha === dateKey && amountEq(total, d.total)) return { folio: d.folio, detalle: 'Cajero/Depósitos: fecha + monto.' }; }
  return null;
}
function matchCombinado(card4, dateKey, total){
  if (isNaN(total) || dateKey === '' || card4 === '') return null;
  for (var t in ingresoTickets){ var tk = ingresoTickets[t];
    if (tk.fecha !== dateKey) continue;
    var protcSum = 0, cardPays = [];
    for (var pi = 0; pi < tk.pays.length; pi++){ var pp = tk.pays[pi];
      if (pp.ref4 !== '' && pp.ref4 === card4) cardPays.push(pp);
      else if (pp.ref4 === '' && !isNaN(pp.pago)) protcSum += pp.pago; }
    if (cardPays.length === 0) continue;
    protcSum = Math.round(protcSum*100)/100;
    var sumCard = 0; for (var cp = 0; cp < cardPays.length; cp++){ sumCard += cardPays[cp].pago; } sumCard = Math.round(sumCard*100)/100;
    var ticketAmts = [sumCard, Math.round((sumCard + protcSum)*100)/100];
    if (!isNaN(tk.total)) ticketAmts.push(tk.total);
    for (var f in cajeroFolios){ var g = cajeroFolios[f];
      if (!folioHasDate(g, dateKey)) continue;
      for (var ta = 0; ta < ticketAmts.length; ta++){
        var combo = Math.round((g.sum + ticketAmts[ta])*100)/100;
        if (amountEq(total, combo))
          return { folio: g.folio, ticket: tk.ticket, detalle: 'Combinado: Folio Ind (' + g.sum + ') + Ticket tarjeta ' + card4 + ' (' + ticketAmts[ta] + ') = ' + total + ', misma fecha.' }; } } }
  return null;
}

// -------- Conciliación (Statement es la base) --------
var out = [];
for (var s = 0; s < stData.length; s++){
  var row = stData[s];
  var codAutRaw = row[ST.codAut];
  var card4 = last4(row[ST.tarjetaNum]);
  var total = parseAmount(row[ST.total]);
  var dateKey = normDate(row[ST.fechaTrx]);
  var checkout = norm(row[ST.checkout]);
  var isCheckout = (checkout === 'si' || checkout === 'sí' || checkout === 'yes' || checkout === 'true' || checkout === '1');

  var cliente = '', origen = '', estado = '', detalle = '', difMonto = '', m = null;
  function difComentario(mm){
    if (mm && !isNaN(mm.diff) && Math.abs(mm.diff) >= 0.01)
      return 'Statement ' + total + ' vs fuente ' + mm.montoFuente + ' = diferencia ' + mm.diff;
    return '';
  }

  if (isCheckout && (isNaN(total) || total < 1)){
    cliente = 'checkout'; origen = 'Checkout'; estado = 'No conciliar';
    detalle = 'Fila marcada como checkout (pre-autorización); excluida de la conciliación.';
  } else if ((m = matchCajeroStrong(codAutRaw, total, dateKey))){
    cliente = m.folio; origen = 'Reporte de Cajero (Folio Ind)'; estado = 'Conciliado Parcial'; detalle = m.detalle; difMonto = difComentario(m);
  } else if ((m = matchDepositoStrong(codAutRaw, total, dateKey))){
    cliente = m.folio; origen = 'Reporte de Cajero (Depósitos)'; estado = 'Conciliado Parcial'; detalle = m.detalle; difMonto = difComentario(m);
  } else if ((m = matchIngreso(card4, dateKey, total))){
    cliente = m.ticket; origen = 'Reporte de Ingresos (Ticket)'; estado = 'Conciliado Parcial'; detalle = m.detalle;
  } else if ((m = matchCajeroByAmountDate(total, dateKey))){
    cliente = m.folio; origen = 'Reporte de Cajero (Folio Ind)'; estado = 'Conciliado Parcial'; detalle = m.detalle;
  } else if ((m = matchDepositoByAmountDate(total, dateKey))){
    cliente = m.folio; origen = 'Reporte de Cajero (Depósitos)'; estado = 'Conciliado Parcial'; detalle = m.detalle;
  } else if ((m = matchCombinado(card4, dateKey, total))){
    cliente = m.folio + ' + ' + m.ticket; origen = 'Cajero (Folio) + Ingresos (Ticket) sumados'; estado = 'Conciliado Total'; detalle = m.detalle;
  } else {
    estado = 'Discrepancia'; detalle = 'No se encontró coincidencia en Cajero ni en Ingresos.';
  }

  out.push({ json: {
    'Fecha Deposito': row[ST.fechaDep] !== undefined ? row[ST.fechaDep] : '',
    'Fecha Transaccion': row[ST.fechaTrx] !== undefined ? row[ST.fechaTrx] : '',
    'Tarjeta': row[ST.tarjeta] !== undefined ? row[ST.tarjeta] : '',
    'Operacion': row[ST.operacion] !== undefined ? row[ST.operacion] : '',
    'Tipo Tarjeta': row[ST.tipoTarjeta] !== undefined ? row[ST.tipoTarjeta] : '',
    'Tarjeta Numero': row[ST.tarjetaNum] !== undefined ? row[ST.tarjetaNum] : '',
    'Cod. Aut.': row[ST.codAut] !== undefined ? row[ST.codAut] : '',
    'Checkout': row[ST.checkout] !== undefined ? row[ST.checkout] : '',
    'Total': row[ST.total] !== undefined ? row[ST.total] : '',
    'cliente': cliente,
    'dif_monto': difMonto,
    'cliente_origen': origen,
    'estado': estado,
    'detalle_conciliacion': detalle,
  }});
}

if (out.length === 0){
  out.push({ json: { aviso: 'No se detectaron filas de datos en el Statement. Revisá la posición de columnas / encabezados.' } });
}
return out;
